function _validateTransfer(address from, address to) internal view {
    uint256 arbitrumChainId = 42161;
    if (
        from != owner() &&
        from != transferAllowedContract &&
        to != transferAllowedContract &&
        isBridgedTokensTransferLocked &&
        (isBridgedTokenHolder[from] || block.chainid == arbitrumChainId) &&
        to != lzEndpoint
    ) {
        revert BridgedTokensTransferLocked();
    }
}

function setTransferAllowedContract(address _transferAllowedContract) external onlyOwner {
    transferAllowedContract = _transferAllowedContract;
    emit TransferAllowedContractUpdated(_transferAllowedContract);
}

function claimTitn(uint256 amount) external nonReentrant {
    require(amount <= claimableTitnPerUser[msg.sender], "Not enough claimable titn");
    if (block.timestamp - launchTime >= 360 days) {
        revert TooLateToClaimRemainingTitn();
    }
    claimedTitnPerUser[msg.sender] += amount;
    claimableTitnPerUser[msg.sender] -= amount;
    totalTitnClaimed += amount;
    totalTitnClaimable -= amount;
    titn.safeTransfer(msg.sender, amount);
    emit ClaimTitn(msg.sender, amount);
}
